mapper.select:
select wms_stock.product_id as product_id, max(md_product.product_code) as product_code, max(md_product.product_name) as product_name, max(md_product.unit_name) as unit_name, ifnull(sum(wms_stock.quantity - ifnull(wms_stock.locked_quantity, 0) - ifnull(wms_stock.frozen_quantity, 0)), 0) as available_quantity from wms_stock left join md_product on wms_stock.product_id = md_product.product_id where 1 = 1
and wms_stock.warehouse_id = #{warehouseId}
group by wms_stock.product_id order by available_quantity desc limit #{rankLimit}
